mapper.select:
/* TM_ME33001_Dao_retrieveCnvrEqpList */ SELECT ecs_elcpwstn_div_cd, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_1002' AND cmmn_cd = A.ecs_elcpwstn_div_cd ) AS ecs_elcpwstn_div_nm, cnvr_eqp_lc_nm, cnvr_eqp_nm, iem_cd, ( SELECT cmmn_cd_nm FROM tc_ecs_cd WHERE use_yn = 'Y' AND cls_cd = 'ECS_2008' AND cmmn_cd = A.iem_cd ) AS iem_nm, mnfct_year, eqp_qty_vu, eror_exam_hist_ym, eror_exam_plan_ym, eror_exam_acmslt_ym, rm_ctnt, frst_regist_dt, frst_rgstr_id, last_updt_dt, last_updusr_id, updt_rsn FROM tm_me33001 A WHERE 1 = 1
AND ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
AND iem_cd IN ( SELECT REGEXP_SUBSTR(#{iemCd}, '[^,]+', 1, LEVEL) FROM DUAL CONNECT BY LEVEL <= LENGTH(REGEXP_REPLACE(#{iemCd}, '[^,]+', '')) + 1 )
ORDER BY ecs_elcpwstn_div_cd, cnvr_eqp_lc_nm, cnvr_eqp_nm, iem_cd

mapper.delete:
/* TM_ME33001_Dao_deleteCnvrEqpList */
DELETE FROM
	tm_me33001
WHERE
	ecs_elcpwstn_div_cd = #{ecsElcpwstnDivCd}
	AND cnvr_eqp_lc_nm = #{cnvrEqpLcNm}
	AND cnvr_eqp_nm = #{cnvrEqpNm}
	AND iem_cd = #{iemCd}
